<?php
namespace App\Modules\Hr\Lifecycle\Actions;use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Lifecycle\Models\HrOnboardingChecklist;use App\Modules\Hr\Lifecycle\Models\HrOnboardingTask;use App\Modules\Hr\Personnel\Actions\CreateEmployeeAction;use App\Modules\Hr\Personnel\Models\HrEmployee;use App\Modules\Hr\Recruitment\Models\HrJobOffer;use Illuminate\Support\Facades\DB;
class HireCandidateAction{public function __construct(private CreateEmployeeAction $createEmployee,private HrAuditService $audit){}public function execute(HrJobOffer $offer,array $data):HrEmployee{abort_unless(auth()->user()?->hasHrPermission('hr.lifecycle.manage')&&auth()->user()?->hasHrPermission('hr.recruitment.approve'),403);$tenant=app(TenantContext::class)->getId();$offer->loadMissing('application.candidate');abort_unless($offer->legal_entity_id===$tenant&&$offer->status==='approved',422,'Yalnız onaylı teklif işe alıma dönüştürülebilir.');abort_if(blank($data['national_id']??null),422,'İşe alım için kimlik numarası zorunludur.');return DB::transaction(function()use($offer,$data,$tenant){$candidate=$offer->application->candidate;$employee=$this->createEmployee->execute(['first_name'=>$candidate->first_name,'last_name'=>$candidate->last_name,'personal_email'=>$candidate->email,'phone'=>$candidate->phone,'national_id'=>$data['national_id'],'employee_number'=>$data['employee_number']??null,'status'=>'active'],['start_date'=>$offer->proposed_start_date,'employment_type'=>$data['employment_type']??'full_time','work_model'=>$data['work_model']??'onsite','position_id'=>$offer->application->posting?->position_id]);$checklist=HrOnboardingChecklist::create(['legal_entity_id'=>$tenant,'employee_id'=>$employee->id,'application_id'=>$offer->application_id,'title'=>'Standart 7/30/60/90 İşe Başlangıç','starts_on'=>$offer->proposed_start_date,'target_completion_on'=>$offer->proposed_start_date->copy()->addDays(90),'status'=>'active','created_by'=>auth()->id()]);foreach([['documents','Özlük belgelerini tamamla',0],['access','Sistem erişimlerini aç',0],['orientation','Oryantasyonu tamamla',7],['day_30','30. gün değerlendirmesi',30],['day_60','60. gün değerlendirmesi',60],['day_90','90. gün değerlendirmesi',90]] as [$key,$title,$days])HrOnboardingTask::create(['legal_entity_id'=>$tenant,'checklist_id'=>$checklist->id,'template_key'=>$key,'title'=>$title,'due_on'=>$offer->proposed_start_date->copy()->addDays($days),'is_required'=>true,'status'=>'pending']);$offer->update(['status'=>'accepted']);$offer->application->update(['status'=>'hired','decision_reason'=>'Teklif aday tarafından kabul edildi.','decided_by'=>auth()->id(),'decided_at'=>now()]);$this->audit->log('candidate_hired_and_onboarding_started',$employee);return $employee;});}}
